import{_ as o,C as n,o as l,c as s,E as i,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const k=JSON.parse('{"title":"Moving to Greece","description":"Immigration pathways and relocation guide for Greece","frontmatter":{"layout":"doc","title":"Moving to Greece","description":"Immigration pathways and relocation guide for Greece"},"headers":[],"relativePath":"europe/greece/moving-there.md","filePath":"europe/greece/moving-there.md","lastUpdated":null}'),g={name:"europe/greece/moving-there.md"};function h(c,e,u,m,f,p){const t=n("Badge");return l(),s("div",null,[i(t,{variant:"green"},{default:a(()=>[...e[0]||(e[0]=[r("EU: Free Movement",-1)])]),_:1}),i(t,{variant:"yellow"},{default:a(()=>[...e[1]||(e[1]=[r("Non-EU: Multiple Visa Options",-1)])]),_:1}),i(t,{variant:"blue"},{default:a(()=>[...e[2]||(e[2]=[r("Digital Nomad Visa (2021)",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="moving-to-greece" tabindex="-1">Moving to Greece <a class="header-anchor" href="#moving-to-greece" aria-label="Permalink to &quot;Moving to Greece&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No formalities</li><li><strong>Over 3 months</strong>: Register with the municipality (Δήμος) and obtain a Registration Certificate (Πιστοποιητικό Εγγραφής)</li><li><strong>Right to work</strong>: Automatic, no work permit needed</li><li><strong>AFM (Tax Number)</strong>: Required for employment and many services</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Longer stays</strong>: Apply for residence permit under: <ul><li><strong>Work visa</strong>: Job offer from Greek employer</li><li><strong>Digital Nomad Visa</strong>: Available since 2021</li><li><strong>Financial Independence Visa</strong>: Proof of sufficient income (pensioners, investors)</li><li><strong>Golden Visa</strong>: Real estate investment of €250,000+</li><li><strong>Family Reunification</strong>: Family ties to Greek resident</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Visa</td><td>Job offer from Greek employer</td><td>1-2 years, renewable</td></tr><tr><td>Digital Nomad Visa</td><td>Remote work, min income ~€3,500/month</td><td>1 year, renewable</td></tr><tr><td>Financial Independence Visa</td><td>Proof of stable income (€2,000+/month)</td><td>2 years, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Greek resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>Golden Visa</td><td>€250,000+ real estate investment</td><td>5 years, renewable</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Greece introduced the <strong>Digital Nomad Visa</strong> (Law 4825/2021):</p><ul><li>For remote workers employed outside Greece</li><li>Minimum income: ~€3,500/month (net)</li><li>Valid for 1 year, renewable for up to 2 additional years</li><li>Can apply at Greek consulates abroad</li><li>Covers family members (spouse, children)</li><li>Can lead to permanent residency after 5 years</li><li>Fast-track processing (30-60 days)</li></ul><h3 id="financial-independence-visa" tabindex="-1">Financial Independence Visa <a class="header-anchor" href="#financial-independence-visa" aria-label="Permalink to &quot;Financial Independence Visa&quot;">​</a></h3><ul><li>For individuals with a stable income (€2,000+/month)</li><li>No work permit — cannot work for a Greek employer</li><li>Valid for 2 years, renewable</li><li>Popular with retirees and remote workers who prefer not to use the DN visa</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-4 months in advance</li><li>[ ] <strong>Healthcare</strong>: Register with EFKA (public insurance) or get private insurance</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (translated to Greek)</li><li>[ ] <strong>Banking</strong>: Consider opening a Greek bank account (National Bank, Piraeus, Alpha)</li><li>[ ] <strong>Housing</strong>: Research rental market (spitogatos.gr, xe.gr)</li><li>[ ] <strong>Language</strong>: Greek essential for bureaucracy; English in tourist areas</li><li>[ ] <strong>Document translation</strong>: Official translations of key documents needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Obtain AFM (tax number) from the tax office (ΔΟΥ)</li><li>[ ] Register with the municipality (Δήμος)</li><li>[ ] Apply for residence permit (non-EU)</li><li>[ ] Register with EFKA (health insurance)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Cosmote, Vodafone, Wind/Nova)</li><li>[ ] Connect with LGBTQ+ organizations (SYNTHESI, Colour Youth)</li><li>[ ] Find a GP and endocrinologist for HRT continuation</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Moderate</strong> — lower than Western Europe</li><li>Monthly rent varies by city: <ul><li>Athens: €400-800</li><li>Thessaloniki: €300-600</li><li>Crete (Heraklion): €300-500</li><li>Islands: €400-700 (higher in tourist season)</li></ul></li><li>Monthly groceries: €250-400</li><li>Dining out: €10-20 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Athens</strong></td><td>Good (Gazi district)</td><td>Best (Alexandras Hospital)</td></tr><tr><td><strong>Thessaloniki</strong></td><td>Moderate</td><td>Limited (AHEPA Hospital)</td></tr><tr><td><strong>Heraklion (Crete)</strong></td><td>Limited</td><td>Limited</td></tr><tr><td><strong>Patras</strong></td><td>Limited</td><td>Limited</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Mediterranean</strong>: Hot, dry summers (25-35°C)</li><li><strong>Mild winters</strong>: (5-15°C, rain)</li><li><strong>Islands</strong>: More temperate with sea breezes</li><li><strong>Northern Greece</strong>: Colder winters with snow possible</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Greek</li><li>English: Widely spoken in tourist areas, less in rural regions</li><li>Greek is essential for government bureaucracy</li><li>Free Greek language courses available through the Ministry of Education</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://migration.gov.gr/" target="_blank" rel="noreferrer">Greek Ministry of Migration &amp; Asylum</a></li><li><a href="https://www.efka.gov.gr/" target="_blank" rel="noreferrer">EFKA (National Insurance)</a></li><li><a href="https://www.workin-greece.gr/" target="_blank" rel="noreferrer">Work in Greece</a></li><li><a href="https://migration.gov.gr/en/visa-for-remote-working/" target="_blank" rel="noreferrer">Digital Nomad Visa Info</a></li><li><a href="https://www.synthesis.gr/" target="_blank" rel="noreferrer">SYNTHESI (Trans Support)</a></li><li><a href="https://www.spitogatos.gr/" target="_blank" rel="noreferrer">Spitogatos (housing)</a></li></ul>',29))])}const y=o(g,[["render",h]]);export{k as __pageData,y as default};
